// MmapBacking + SimpleMemory glued together: writes via TLM land on disk,
// bytes pre-placed by an external owner are visible via TLM reads.

#include "platform/mmap_backing.hpp"
#include "platform/simple_memory.hpp"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <fcntl.h>
#include <sys/mman.h>
#include <unistd.h>

#include <array>
#include <cstdio>
#include <cstdlib>
#include <filesystem>
#include <string>

namespace {
auto unique_tmp_path(const char* tag) -> std::string
{
  auto p = std::filesystem::temp_directory_path()
           / (std::string{"vsim_shared_mem_"} + tag + "_"
              + std::to_string(::getpid()));
  std::filesystem::remove(p);
  return p.string();
}
}  // namespace

TEST_CASE("write through SimpleMemory shows up on disk through MmapBacking")
{
  const auto path = unique_tmp_path("write");
  constexpr std::size_t kSize = 0x1000;
  constexpr uint64_t kBase = 0x1000;

  MmapBacking backing(path, kSize);
  SimpleMemory<32> mem{
    "mem", MemoryRegion{kBase, kBase + kSize - 1},
    MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
                 SimpleMemory<32>::INVALID_ADDRESS},
    backing.span()};

  std::array<uint8_t, 4> bytes{0xde, 0xad, 0xbe, 0xef};
  tlm::tlm_generic_payload gp;
  gp.set_command(tlm::TLM_WRITE_COMMAND);
  gp.set_address(kBase + 0x100);
  gp.set_data_ptr(bytes.data());
  gp.set_data_length(bytes.size());
  gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
  sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
  mem.b_transport(gp, delay);
  REQUIRE(gp.get_response_status() == tlm::TLM_OK_RESPONSE);

  // Independent reader: open the file fresh and mmap it.
  const int fd = ::open(path.c_str(), O_RDONLY);
  REQUIRE(fd >= 0);
  void* p = ::mmap(nullptr, kSize, PROT_READ, MAP_SHARED, fd, 0);
  REQUIRE(p != MAP_FAILED);
  auto* file_bytes = static_cast<const uint8_t*>(p);
  CHECK(file_bytes[0x100] == 0xde);
  CHECK(file_bytes[0x101] == 0xad);
  CHECK(file_bytes[0x102] == 0xbe);
  CHECK(file_bytes[0x103] == 0xef);
  ::munmap(p, kSize);
  ::close(fd);
  std::filesystem::remove(path);
}

TEST_CASE("bytes pre-placed in the file are read back through SimpleMemory")
{
  const auto path = unique_tmp_path("read");
  constexpr std::size_t kSize = 0x1000;
  constexpr uint64_t kBase = 0x1000;

  MmapBacking backing(path, kSize);
  // Outside writer (e.g. QEMU side) places known bytes via the same mapping.
  backing.span()[0x200] = 0xca;
  backing.span()[0x201] = 0xfe;
